VALUES
  ('judicial-57f41407-moex-00513', 'judicial-57f41407', 'judicial-57f41407-moex-112-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '行政處分係於民國110年5月3日星期一送達於訴願人之代理人，訴願人之代理人設址桃園市，訴願人設 址於受理訴願機關所在地臺北市，訴願人之訴願書於110年6月3日星期三送達原處分機關，試問受理訴 願機關應為如何之決定？', '["訴願逾期，訴願不受理", "訴願逾期，駁回其訴願", "訴願不合法定程式，通知補正", "訴願未逾期，應為實體審理"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "53559b9cd29b", "answer_pdf_sha1": "a4ca9f3152ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0316", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00514', 'judicial-57f41407', 'judicial-57f41407-moex-112-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '甲欠繳稅款經財政部函請內政部移民署限制出境，同時通知甲。甲不服，提起訴願。惟於訴願審理中，財 政部又函請內政部移民署解除對甲之出境限制，同日並通知甲，則受理訴願機關應為如何之處理？', '["本件行政處分已不存在，訴願應不受理", "本件行政處分已不存在，訴願應予駁回", "本件原行政處分違法，應為撤銷原處分", "本件原行政處分合法，訴願應予駁回"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "53559b9cd29b", "answer_pdf_sha1": "a4ca9f3152ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0316", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00515', 'judicial-57f41407', 'judicial-57f41407-moex-112-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '關於訴願之撤回，下列敘述何者錯誤？', '["訴願提起後，於決定書送達前，訴願人得撤回之", "訴願經撤回後，不得復提起同一之訴願", "訴願經撤回者，應為不受理之決定", "對已撤回之訴願事件重行提起訴願者，應為不受理之決定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "53559b9cd29b", "answer_pdf_sha1": "a4ca9f3152ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0316", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00516', 'judicial-57f41407', 'judicial-57f41407-moex-112-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '人民因中央或地方機關對其依法申請之案件，於法定期間內應作為而不作為，認為有損害其權利或利益者， 得依法提起訴願。訴願繫屬後，受理訴願機關未為決定前，應作為之機關已作成行政處分時，受理訴願機 關之處理，下列敘述何者錯誤？', '["如果應作為之機關所為之處分是有利於訴願人，則訴願管轄機關應為訴願不受理", "如果應作為之機關所為之處分是有利於訴願人，則訴願管轄機關應駁回其訴願", "如果應作為之機關所為之處分是全部拒絕當事人之申請時，訴願管轄機關應續行訴願程序", "如果應作為之機關所為之處分是全部拒絕當事人之申請時，訴願管轄機關應對處分機關嗣後所為之處分 併為實體審查"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "53559b9cd29b", "answer_pdf_sha1": "a4ca9f3152ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0316", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00517', 'judicial-57f41407', 'judicial-57f41407-moex-112-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '下列何者非屬民事訴訟法規定之指定管轄事由？', '["同一訴訟，數法院有管轄權者", "因管轄區域境界不明，致不能辨別有管轄權之法院者", "有管轄權之法院，因法律或事實不能行使審判權", "有管轄權之法院，因特別情形，由其審判恐難期公平者"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "53559b9cd29b", "answer_pdf_sha1": "a4ca9f3152ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0316", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00518', 'judicial-57f41407', 'judicial-57f41407-moex-112-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '下列關於民事訴訟能力之敘述，何者錯誤？', '["受監護宣告者，無訴訟能力", "受輔助宣告者起訴或上訴，無須經輔助人同意", "外國人依其本國法律無訴訟能力，而依中華民國法律有訴訟能力者，視為有訴訟能力", "當事人訴訟能力有欠缺可以補正者，審判長應定期間命其補正"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "53559b9cd29b", "answer_pdf_sha1": "a4ca9f3152ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0316", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00519', 'judicial-57f41407', 'judicial-57f41407-moex-112-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '下列關於民事訴訟和解之敘述，何者正確？', '["當事人和解之意思已甚接近，法院得依當事人一造之聲請提出和解方案，並送達於兩造當事人發生效力", "和解成立者，當事人得於成立之日起三個月內聲請退還其於該審級所繳之裁判費之全額", "和解基於當事人間通謀虛偽意思表示而無效者，當事人得請求法院繼續審判", "第三人經法院許可，得參加和解，第三人參加和解成立者，與確定判決有同一效力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "53559b9cd29b", "answer_pdf_sha1": "a4ca9f3152ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0316", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00520', 'judicial-57f41407', 'judicial-57f41407-moex-112-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '關於民事訴訟代理人之委任，下列敘述何者正確？', '["民事訴訟行為，均須委任訴訟代理人為之", "於上訴第三審之訴訟，上訴人原則上應委任律師為訴訟代理人", "經對造之許可，當事人得委任非律師為訴訟代理人", "訴訟代理人之委任，僅得以書面為之，言詞委任均不生委任效果"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "53559b9cd29b", "answer_pdf_sha1": "a4ca9f3152ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0316", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00521', 'judicial-57f41407', 'judicial-57f41407-moex-112-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '甲將電視機及遙控器出賣於乙，但只交付電視機。乙如何請求甲交付遙控器？', '["基於遙控器所有權", "基於該買賣契約", "基於占有物回復請求權", "基於遺失物回復請求權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "53559b9cd29b", "answer_pdf_sha1": "a4ca9f3152ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0316", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00522', 'judicial-57f41407', 'judicial-57f41407-moex-112-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '甲購買土地，並借用乙之名義辦理登記，乙擅自將該地出售於知情之丙。乙丙間移轉該土地所有權行為之 效力為何？', '["有效", "無效", "效力未定", "得撤銷"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "53559b9cd29b", "answer_pdf_sha1": "a4ca9f3152ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0316", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL)
